#include "curlcheck.h"

#include "memdebug.h"

static CURLcode unit_setup(void)
{
  return CURLE_OK;
}

static void unit_stop(void)
{
}

UNITTEST_START

{
  CURL *curl = curl_easy_init();
  if(!curl) {
    fprintf(stderr, "curl_easy_init failed\n");
    return TEST_ERR_MAJOR_BAD;
  }

  /* Test setting H3 stream priority with urgency only */
  CURLcode ret = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=0");
  if(ret != CURLE_OK) {
    fprintf(stderr, "Failed to set H3_STREAM_PRIORITY with u=0: %s\n",
            curl_easy_strerror(ret));
    curl_easy_cleanup(curl);
    return TEST_ERR_MAJOR_BAD;
  }

  /* Test setting H3 stream priority with urgency 7 */
  ret = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=7");
  if(ret != CURLE_OK) {
    fprintf(stderr, "Failed to set H3_STREAM_PRIORITY with u=7: %s\n",
            curl_easy_strerror(ret));
    curl_easy_cleanup(curl);
    return TEST_ERR_MAJOR_BAD;
  }

  /* Test setting H3 stream priority with urgency and incremental flag */
  ret = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=3,i");
  if(ret != CURLE_OK) {
    fprintf(stderr, "Failed to set H3_STREAM_PRIORITY with u=3,i: %s\n",
            curl_easy_strerror(ret));
    curl_easy_cleanup(curl);
    return TEST_ERR_MAJOR_BAD;
  }

  /* Test with invalid urgency (out of range) */
  ret = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=8");
  if(ret != CURLE_BAD_FUNCTION_ARGUMENT) {
    fprintf(stderr, "Expected CURLE_BAD_FUNCTION_ARGUMENT for u=8, got %s\n",
            curl_easy_strerror(ret));
    curl_easy_cleanup(curl);
    return TEST_ERR_MAJOR_BAD;
  }

  /* Test with invalid urgency (negative) */
  ret = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=-1");
  if(ret != CURLE_BAD_FUNCTION_ARGUMENT) {
    fprintf(stderr, "Expected CURLE_BAD_FUNCTION_ARGUMENT for u=-1, got %s\n",
            curl_easy_strerror(ret));
    curl_easy_cleanup(curl);
    return TEST_ERR_MAJOR_BAD;
  }

  /* Test with invalid format */
  ret = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "invalid");
  if(ret != CURLE_BAD_FUNCTION_ARGUMENT) {
    fprintf(stderr, "Expected CURLE_BAD_FUNCTION_ARGUMENT for invalid format, got %s\n",
            curl_easy_strerror(ret));
    curl_easy_cleanup(curl);
    return TEST_ERR_MAJOR_BAD;
  }

  curl_easy_cleanup(curl);
}

UNITTEST_STOP

