#include <stdio.h>
#include <string.h>

int main() {
    /* Test the parsing logic */
    const char *test_cases[] = {
        "u=0",
        "u=7",
        "u=3,i",
        "u=0,i",
        NULL
    };

    int i = 0;
    while(test_cases[i]) {
        const char *priority_str = test_cases[i];
        int urgency = 3;
        int incremental = 0;

        if(sscanf(priority_str, "u=%d", &urgency) == 1) {
            if((urgency < 0) || (urgency > 7)) {
                printf("Invalid urgency: %s\n", priority_str);
            } else {
                if(strchr(priority_str, 'i'))
                    incremental = 1;
                printf("Valid: %s -> urgency=%d, incremental=%d\n", 
                       priority_str, urgency, incremental);
            }
        } else {
            printf("Invalid format: %s\n", priority_str);
        }
        i++;
    }

    return 0;
}
EOF
gcc /tmp/test_parsing.c -o /tmp/test_parsing && /tmp/test_parsing
